// Build Job Folder â€” computes Drive folder name and filenames
// Mode: Run Once for Each Item
const job = $('Set Inputs').first().json.job_result;
const config = $('Set Inputs').first().json.config;
const stripEquals = (val) =>
  (typeof val === 'string' && val.startsWith('=')) ? val.substring(1) : val;
const company = job.job?.company || 'Unknown';
const title = job.job?.title || 'Untitled';
const today = new Date();
const year = today.getFullYear();
const dateStr = today.toISOString().split('T')[0];
// Folder name is dated by the job's posted_at (fallback discovered_at, then today)
// so reruns of the same job produce a STABLE folder name â€” prevents date-drift duplicates.
const toDateStr = (v) => {
  if (!v) return '';
  const s = String(v).trim();
  if (!s) return '';
  // Accept ISO timestamps and plain dates; take the YYYY-MM-DD portion.
  const m = s.match(/^\d{4}-\d{2}-\d{2}/);
  if (m) return m[0];
  const d = new Date(s);
  return isNaN(d.getTime()) ? '' : d.toISOString().split('T')[0];
};
const postedDateStr =
  toDateStr(job.job?.posted_at) ||
  toDateStr(job.job?.discovered_at) ||
  dateStr;
if (!toDateStr(job.job?.posted_at) && !toDateStr(job.job?.discovered_at)) {
  console.log(`[Build Job Folder] WARNING: no posted_at/discovered_at for "${company} â€” ${title}"; folder dated with today (${dateStr}) â€” folder name will not be stable across runs.`);
}
const firstName = stripEquals(config.applicant_first_name) || 'Unknown';
const lastName = stripEquals(config.applicant_last_name) || 'Applicant';
const fullName = `${firstName} ${lastName}`;
// Root folder now sourced from Data Loader (via Set Inputs), not config.drive_root_folder_id
const driveRootFolderId = stripEquals($('Set Inputs').first().json.root_folder_id);
function sanitize(s) {
  return String(s).replace(/[\/\\:*?"<>|]/g, '').replace(/\s+/g, ' ').trim();
}
function truncateAtWord(s, maxLen) {
  if (s.length <= maxLen) return s;
  const cut = s.substring(0, maxLen).trim();
  const lastSpace = cut.lastIndexOf(' ');
  return (lastSpace > 15 ? cut.substring(0, lastSpace) : cut).trim();
}
const safeCompany = sanitize(company);
const safeTitle = sanitize(title);
const shortTitle = truncateAtWord(safeTitle, 35);
const folderName = `${safeCompany} â€“ ${shortTitle} â€“ ${postedDateStr}`;
const filenames = {
  resume: `${fullName}_Resume- ${safeTitle}-${year}`,
  cover_letter: `${fullName}_Cover Letter- ${safeTitle}-${year}`,
  job_description: `Job Description- ${safeTitle}-${safeCompany}-${dateStr}`,
  assessment: `${fullName}_Assessment- ${safeTitle}-${year}`
};
console.log(`[Build Job Folder] Folder: ${folderName}`);
return {
  json: {
    ...job,
    folder_name: folderName,
    filenames,
    applicant: { first_name: firstName, last_name: lastName, full_name: fullName },
    date: dateStr,
    posted_date: postedDateStr,
    resume_folder_url: job.job?.resume_folder_url || '',
    year,
    drive_root_folder_id: driveRootFolderId
  }
};

// Build JD HTML â€” formats job description as styled HTML for archival
// Mode: Run Once for Each Item
const job = $('Set Inputs').first().json.job_result;
const description = job.job?.description_html || '';
const company = job.job?.company || 'Unknown Company';
const title = job.job?.title || 'Unknown Role';
const url = job.job?.url || '';
const today = new Date().toISOString().split('T')[0];
if (!description || description.length < 50) {
  throw new Error('[Build JD HTML] No job description to format');
}
function cleanDescription(text) {
  return text
    .replace(/\r\n/g, '\n').replace(/\r/g, '\n')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n\n')
    .replace(/<[^>]+>/g, '')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/&nbsp;/g, ' ')
    .replace(/\n{3,}/g, '\n\n').trim();
}
const cleaned = cleanDescription(description);
const escaped = cleaned.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const paragraphs = escaped.split(/\n\n+/);
const bodyHTML = paragraphs.map(p => p.trim()).filter(p => p)
  .map(p => '<p>' + p.replace(/\n/g, '<br/>') + '</p>').join('\n');
const fullHTML = `<!DOCTYPE html>
<html><head><meta charset="UTF-8"><title>${title} - ${company}</title>
<style>
@page { size: letter; margin: 0.7in; }
body { font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif; font-size: 11pt; line-height: 1.5; color: #222; margin: 0; }
.metadata { border-bottom: 1px solid #ccc; padding-bottom: 12px; margin-bottom: 20px; }
.metadata h1 { font-size: 16pt; margin: 0 0 4px 0; color: #111; }
.metadata .company { font-size: 12pt; color: #1a4d8f; font-weight: 600; margin: 0; }
.metadata .meta-line { font-size: 9pt; color: #666; margin: 6px 0 0 0; }
.metadata a { color: #1a4d8f; text-decoration: none; }
p { margin: 8px 0; }
</style></head><body>
<div class="metadata">
<h1>${title}</h1>
<p class="company">${company}</p>
<p class="meta-line">Archived: ${today} Â· <a href="${url}">${url}</a></p>
</div>
${bodyHTML}
</body></html>`;
console.log(`[Build JD HTML] Generated ${fullHTML.length} chars HTML`);
return { json: { ...job, jd_html: fullHTML } };

const job = $('Build JD HTML').item.json;
const filename = $('Build Job Folder').item.json.filenames.job_description;

if (!job.jd_html) {
  throw new Error('[Convert JD to Binary] No jd_html to convert');
}

const NodeBuffer = globalThis['Buffer'];

return {
  json: job,
  binary: {
    data: {
      data: NodeBuffer.from(job.jd_html).toString('base64'),
      mimeType: 'text/html',
      fileName: `${filename}.html`
    }
  }
};

// Set Inputs â€” Recorder Sub-Workflow
// Normalizes inputs from the orchestrator's Execute Workflow call.
const trigger = $input.first()?.json || {};
function strip(val) {
  if (val === null || val === undefined) return '';
  if (typeof val !== 'string') return val;
  let cleaned = val;
  while (cleaned.length > 0 && cleaned.charAt(0) === '=') {
    cleaned = cleaned.substring(1);
  }
  return cleaned;
}
const jobResult = trigger.job_result || {};
const config = trigger.config || {};
// Validation
if (!jobResult || typeof jobResult !== 'object' || !jobResult.job) {
  throw new Error('[Recorder Set Inputs] job_result missing or invalid; expected an object with a `job` field');
}
if (!config || typeof config !== 'object') {
  throw new Error('[Recorder Set Inputs] config missing or invalid');
}
console.log(`[Recorder Set Inputs] Job: ${jobResult.job?.company || 'unknown'} â€” ${jobResult.job?.title || 'unknown'}`);
console.log(`[Recorder Set Inputs] config keys: ${Object.keys(config).length}`);
return [{
  json: {
    job_result: jobResult,
    config,
    // Drive root folder now comes from Data Loader via the orchestrator, not config
    root_folder_id: strip(trigger.root_folder_id)
  }
}];

const item = $('Build Assessment HTML').item.json;
const filename = $('Build Job Folder').item.json.filenames.assessment;

if (!item.html) {
  throw new Error('[Convert Assessment to Binary] No assessment HTML to convert');
}

const NodeBuffer = globalThis['Buffer'];

return {
  json: item,
  binary: {
    data: {
      data: NodeBuffer.from(item.html).toString('base64'),
      mimeType: 'text/html',
      fileName: `${filename}.html`
    }
  }
};

const data = $('Set Inputs').first().json.job_result || {};
const folderId = $('Finalize Job Folder').item?.json?.job_folder_id || '';
const runId = data.application_run_id;

const job = data.job || {};
const scorer = data.scorer || {};

// processed_status now comes from Log Job Result (per-job): 'done' | 'error' | 'insufficient_credit'.
// For a credit-failed job we write 'insufficient_credit' (the frontend's re-queue signal) and
// leave the application fields BLANK so the re-queued row starts clean â€” no stale folder URL,
// score, or generated_at from a build that didn't complete.
const status = data.processed_status || 'done';
const isClean = status === 'done';

return {
  json: {
    url: job.url,
    application_run_id: runId,
    processed_status: status,
    prompt_warnings: '',
    resume_folder_url: isClean && folderId ? `https://drive.google.com/drive/folders/${folderId}` : '',
    resume_generated_at: isClean ? new Date().toISOString() : '',
    resume_fit_score: isClean && (typeof scorer.overall_score === 'number') ? scorer.overall_score : '',
    recommendation: isClean ? (scorer.recommendation || '') : '',
    resume_score_rationale: isClean ? (scorer.rationale || scorer.score_rationale || '') : '',
    application_tokens_in: data.application_tokens?.input || 0,
    application_tokens_out: data.application_tokens?.output || 0,
    application_cost_usd: data.application_cost ? Number(data.application_cost.toFixed(6)) : 0,
    total_tokens_in: data.total_tokens?.input || 0,
    total_tokens_out: data.total_tokens?.output || 0,
    total_cost: data.total_cost ? Number(data.total_cost.toFixed(6)) : 0
  }
};

const data = $('Set Inputs').first().json.job_result || {};
const job = data.job || {};
const verifier = data.verifier || {};
const coverVerifier = data.cover_verifier || {};
const critic = data.critic || {};
const scorer = data.scorer || {};

const esc = (s) => String(s || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');

const list = (items, key) => {
  if (!Array.isArray(items) || items.length === 0) return '<p><em>None.</em></p>';
  return '<ul>' + items.map(it => {
    const text = (typeof it === 'string') ? it : (it[key] || JSON.stringify(it));
    return `<li>${esc(text)}</li>`;
  }).join('') + '</ul>';
};

const verifierSection = (v, title) => {
  if (!v || Object.keys(v).length === 0) return `<h2>${title}</h2><p><em>No output.</em></p>`;
  return `
    <h2>${title}</h2>
    <p><strong>Verdict:</strong> ${esc(v.verdict)}</p>
    <p><strong>Summary:</strong> ${esc(v.summary)}</p>
    <p><strong>Claims:</strong> ${v.claim_count || 0} total Â· ${v.supported_count || 0} supported Â· ${v.unsupported_count || 0} unsupported</p>
    <h3>Issues</h3>
    ${list(v.issues, 'description')}
  `;
};

const html = `<!DOCTYPE html><html><head><meta charset="utf-8"><title>Assessment</title></head><body style="font-family: Arial, sans-serif; max-width: 800px; line-height: 1.5;">
<h1>Assessment: ${esc(job.company)} â€” ${esc(job.title)}</h1>
<p><a href="${esc(job.url)}">${esc(job.url)}</a></p>

<h2>Score</h2>
<p><strong>Overall:</strong> ${scorer.overall_score ?? 'N/A'} Â· <strong>Recommendation:</strong> ${esc(scorer.recommendation)}</p>
<p><strong>Rationale:</strong> ${esc(scorer.rationale || scorer.score_rationale)}</p>
<h3>Strengths</h3>
${list(scorer.strengths)}
<h3>Gaps</h3>
${list(scorer.gaps)}

${verifierSection(verifier, 'Resume Verifier')}
${verifierSection(coverVerifier, 'Cover Letter Verifier')}

<h2>Critic</h2>
<p>${esc(critic.overall_assessment)}</p>
<p><strong>Issue counts:</strong> ${critic.total_issues || 0} total Â· ${critic.critical_count || 0} critical Â· ${critic.major_count || 0} major Â· ${critic.minor_count || 0} minor</p>
<h3>Critical</h3>
${list(critic.critical_issues, 'description')}
<h3>Major</h3>
${list(critic.major_issues, 'description')}
<h3>Minor</h3>
${list(critic.minor_issues, 'description')}
<h3>Preserve (don't change)</h3>
${list(critic.preserve)}
</body></html>`;

return {
  json: {
    file_name: 'Assessment.html',
    html: html
  }
};

// Resolve Job Folder Query â€” builds the name-search query for the job folder.
// Dedup key = folder name (stable, posted-date based). A user rename intentionally
// branches to a new folder. Searches for the job folder by name UNDER the year folder.
// Mode: Run Once for Each Item
const folderName = $('Build Job Folder').first().json.folder_name;
const yearFolderId = $json.id; // year folder id, resolved by the upstream Merge

if (!folderName) {
  throw new Error('[Resolve Job Folder Query] folder_name missing from Build Job Folder');
}
if (!yearFolderId) {
  throw new Error('[Resolve Job Folder Query] year folder id missing from Merge ($json.id)');
}

// Escape single quotes in the folder name for the Drive query (apostrophes in titles).
const safeName = String(folderName).replace(/'/g, "\\'");
const query = `name = '${safeName}' and '${yearFolderId}' in parents and trashed = false`;

console.log(`[Resolve Job Folder Query] Searching for job folder: "${folderName}" under year ${yearFolderId}`);

return {
  json: {
    job_folder_query: query,
    job_folder_name: folderName,
    year_folder_id: yearFolderId
  }
};

// Finalize Job Folder â€” emits the canonical job_folder_id regardless of source
// (found-by-name reuse, or newly created). Downstream consumers read job_folder_id
// and resume_folder_url from here, not from Create Drive Folder.
// Mode: Run Once for Each Item
const item = $json || {};

// Both Search Job Folder (found) and Create Drive Folder (created) emit { id, name, ... }.
const folderId = item.id;

if (!folderId) {
  throw new Error('[Finalize Job Folder] No folder id resolved â€” neither search nor create produced an id');
}

const resumeFolderUrl = `https://drive.google.com/drive/folders/${folderId}`;

console.log(`[Finalize Job Folder] job_folder_id=${folderId}`);

return {
  json: {
    job_folder_id: folderId,
    resume_folder_url: resumeFolderUrl
  }
};

// Prepare Recorder Input â€” adapts the ORIGINAL build's job_result into the shape
// Resume Recorder expects (it was built for the refinement path). Maps the built
// resume into jr.refiner.*, stamps a v1 'original' resume_row, aliases cost, and
// stamps verifier.ran = true (the build path always runs the verifier; unlike the
// refine path, there is no gating, so the build's verifier object carries no `ran`
// flag and Build Resume Row would otherwise default ran_verifier to FALSE).
// Refinement path builds its own resume_row + refiner, so this node is original-only.
const jr = $('Set Inputs').first().json.job_result || {};

const jobId = jr.job?.job_id || jr.job_id || '';

const adapted = {
  ...jr,
  // Resume Recorder reads the new markdown off jr.refiner.*
  refiner: {
    resume_markdown: jr.resume?.markdown || '',
    tokens: jr.resume?.tokens || { input: 0, output: 0 }
  },
  // Build always runs the verifier; ensure ran:true so ran_verifier records TRUE.
  verifier: {
    ...(jr.verifier || {}),
    ran: true
  },
  // v1 original row descriptor (refinement path supplies its own)
  resume_row: {
    version: 1,
    source: 'original',
    parent_resume_id: '',
    refinement_instructions: '',
    score_delta: null
  },
  // Resume Recorder reads jr.refinement_cost; original build calls it application_cost
  refinement_cost: (typeof jr.application_cost === 'number') ? jr.application_cost : 0
};

return [{ json: adapted }];

// Prepare Cover Recorder Input â€” adapts the build's job_result into the shape
// Cover Letter Recorder expects. Today the cover letter is original-only (v1), so
// this stamps a v1 'original' cover_letter_row descriptor and passes the native
// cover_letter / cover_verifier objects through untouched. When cover-letter
// refinement is added later, the refine path will supply its own cover_letter_row.
const jr = $('Set Inputs').first().json.job_result || {};

const adapted = {
  ...jr,
  cover_letter_row: {
    version: 1,
    source: 'original',
    parent_cover_letter_id: '',
    refinement_instructions: ''
  }
};

return [{ json: adapted }];
